import{_ as r,o as t,c as n,j as a,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灰烬天堂","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/灰烬天堂.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/灰烬天堂.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/灰烬天堂.md"};function l(_,e,i,c,p,b){return t(),n("div",null,[...e[0]||(e[0]=[a("h1",{id:"灰烬天堂",tabindex:"-1"},[s("灰烬天堂 "),a("a",{class:"header-anchor",href:"#灰烬天堂","aria-label":'Permalink to "灰烬天堂"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),o('<h1 id="灰烬天堂-1" tabindex="-1">灰烬天堂 <a class="header-anchor" href="#灰烬天堂-1" aria-label="Permalink to &quot;灰烬天堂&quot;">​</a></h1><p>灰烬天堂【Ember Celica】<br> A+4000<br> 使用天生武器进行战斗时，提供10点攻击上的附加成功。<br> 武器分类：臂铠/拳套<br> 双重远程猎枪臂铠（Dual Ranged Shot Gauntlets，DRSG），平时以护腕形态收在Yang手腕上。在需要时，臂铠可在短时间内完成变形并覆盖Yang的左右前臂。臂铠具有枪击功能，单发弹药容量为12发子弹，总体弹药容量是24发。<br> 这把武器在进行攻击时，拥有两种攻击模式，使用者在进行攻击前需要自行选择<br> 近战模式：使用臂铠的本体击打目标造成伤害，这次攻击可以极大的破坏目标，本次攻击的成功数增加50%，成功数增加效果每轮只能生效一次。<br> 远程模式：使用装填的霰弹进行射击，拥有240米的射程，在计算攻击检定时，依旧以武技，专业：臂铠/拳套进行计算。<br> 合击：每轮一次，在使用近战模式攻击后，若再使用霰弹射击模式，则这次攻击会造成双倍伤害，同时使用者需要进行一个RD10自然骰，如果成功数大于等于8，则此次攻击中本武器带来的附加成功加倍计算，如果小于8，则会对使用者造成本次攻击出数一半的冲击点数。成功使用该能力后，可以借助霰弹的冲击力进行一次移动，也可以在其他情况下，轰击地面、障碍物等进行移动、偏转。<br> 如果持有者的手臂被斩断等等，则臂铠本身会充当使用者的双臂，继续进行战斗，并可以正常的发挥作用。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
